(function(){
  try {
    var text = document.body.innerText;
    var result = {};
    var m;
    m = text.match(/第[0-9]+块田/);
    if (m) result.fieldsInfo = m[0];
    m = text.match(/(idle|未开垦|已整地|已播种|育苗|移栽|生长|成熟)/);
    if (m) result.fieldStage = m[0];
    m = text.match(/进度[：:]*\s*([0-9]+)%/);
    if (m) result.progress = m[1];
    m = text.match(/作物[：:]\s*([^\n]+)/);
    if (m) result.crop = m[1];
    return JSON.stringify(result);
  } catch(e) {
    return JSON.stringify({error: e.message});
  }
})()
